+func TestLoadBuiltinRoleDefinition_Autonomous(t *testing.T) {
+	// Verify the Autonomous field is correctly loaded from TOML
+	autonomousRoles := map[string]bool{
+		"polecat":  true,
+		"witness":  true,
+		"refinery": true,
