+		"dog":      true,
+		"mayor":    false,
+		"crew":     false,
+	}
+
+	for role, wantAutonomous := range autonomousRoles {
+		t.Run(role, func(t *testing.T) {
+			def, err := loadBuiltinRoleDefinition(role)
