+				t.Fatalf("loadBuiltinRoleDefinition(%s) error: %v", role, err)
+			}
+			if def.Autonomous != wantAutonomous {
+				t.Errorf("Autonomous = %v, want %v", def.Autonomous, wantAutonomous)
+			}
+		})
+	}
